<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Maze Explorer Bots</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #1a1a2e;
    color: #e0e0e0;
    font-family: 'Segoe UI', system-ui, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    min-height: 100vh;
    padding: 16px;
  }
  #controls {
    display: flex;
    gap: 16px;
    align-items: center;
    margin-bottom: 12px;
    flex-wrap: wrap;
    justify-content: center;
  }
  #controls button {
    padding: 8px 20px;
    font-size: 15px;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    background: #0f3460;
    color: #e0e0e0;
    font-weight: 600;
    transition: background 0.2s;
  }
  #controls button:hover { background: #16213e; }
  #controls button:active { background: #1a1a5e; }
  .stat {
    font-size: 15px;
    font-weight: 600;
    color: #e94560;
    min-width: 120px;
    text-align: center;
  }
  #maze {
    border: 3px solid #e94560;
    border-radius: 4px;
    background: #0a0a1a;
    display: block;
  }
  #legend {
    margin-top: 10px;
    font-size: 12px;
    color: #888;
    text-align: center;
  }
</style>
</head>
<body>
<div id="controls">
  <button id="reset">Reset</button>
  <div class="stat">Completed: <span id="completed">0</span>/24</div>
  <div class="stat">Time: <span id="timer">0</span> ticks</div>
</div>
<canvas id="maze" width="600" height="600"></canvas>
<div id="legend">24 bots explore the maze to find the exit. Timer freezes when all arrive.</div>

<script>
(function() {
  "use strict";

  // --- Seeded PRNG (mulberry32) ---
  function mulberry32(seed) {
    let s = seed | 0;
    return function() {
      s |= 0; s = s + 0x6D2B79F5 | 0;
      let t = Math.imul(s ^ s >>> 15, 1 | s);
      t = t + Math.imul(t ^ t >>> 7, 61 | t) ^ t;
      return ((t ^ t >>> 14) >>> 0) / 4294967296;
    };
  }

  // --- Constants ---
  const MAZE_ROWS = 20;
  const MAZE_COLS = 20;
  const NUM_BOTS = 24;
  const CELL_SIZE = 30;
  const WALL_THICKNESS = 2;
  const CANVAS_SIZE = MAZE_ROWS * CELL_SIZE + WALL_THICKNESS * 2;

  // --- Maze generation (iterative DFS / recursive backtracker) ---
  function generateMaze(rows, cols, rng) {
    const grid = [];
    for (let r = 0; r < rows; r++) {
      grid[r] = [];
      for (let c = 0; c < cols; c++) {
        grid[r][c] = { n: true, e: true, s: true, w: true, visited: false };
      }
    }

    const stack = [];
    const startR = 0, startC = 0;
    grid[startR][startC].visited = true;
    stack.push({ r: startR, c: startC });

    const dirs = [
      { dr: -1, dc: 0, wall: 'n', opp: 's' },
      { dr: 0, dc: 1, wall: 'e', opp: 'w' },
      { dr: 1, dc: 0, wall: 's', opp: 'n' },
      { dr: 0, dc: -1, wall: 'w', opp: 'e' }
    ];

    while (stack.length > 0) {
      const current = stack[stack.length - 1];
      const neighbors = [];
      for (const d of dirs) {
        const nr = current.r + d.dr;
        const nc = current.c + d.dc;
        if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && !grid[nr][nc].visited) {
          neighbors.push({ r: nr, c: nc, dir: d });
        }
      }
      if (neighbors.length > 0) {
        const chosen = neighbors[Math.floor(rng() * neighbors.length)];
        // Remove walls
        grid[current.r][current.c][chosen.dir.wall] = false;
        grid[chosen.r][chosen.c][chosen.dir.opp] = false;
        grid[chosen.r][chosen.c].visited = true;
        stack.push({ r: chosen.r, c: chosen.c });
      } else {
        stack.pop();
      }
    }

    return grid;
  }

  // --- Bot class ---
  function createBot(id, seed, mazeRows, mazeCols) {
    const rng = mulberry32(seed);
    // Shuffle direction order for this bot
    const dirOrder = [0, 1, 2, 3];
    for (let i = dirOrder.length - 1; i > 0; i--) {
      const j = Math.floor(rng() * (i + 1));
      [dirOrder[i], dirOrder[j]] = [dirOrder[j], dirOrder[i]];
    }

    return {
      id: id,
      r: 0,
      c: 0,
      // Smooth rendering
      displayR: 0,
      displayC: 0,
      // Path history
      path: [{ r: 0, c: 0 }],
      // Dead ends marked by this bot
      deadEnds: [],
      // Stack for DFS backtracking
      stack: [{ r: 0, c: 0 }],
      // Edges traversed by this bot: key "r1,c1,r2,c2" -> count
      edgeCount: {},
      // Finished state
      finishTick: null,
      // Color
      color: `hsl(${(id * 15) % 360}, 80%, 60%)`,
      // Direction preference order
      dirOrder: dirOrder,
      // Current direction being explored (for backtracking)
      // We'll use the stack approach: when stuck, pop from stack
      // and move toward the popped cell
      // State machine: 'exploring' or 'backtracking'
      state: 'exploring',
      // Target for backtracking
      backtrackTarget: null,
      // Already explored cells (fully visited neighbors)
      explored: new Set(),
      // Count of explored neighbors
      exploredCount: 0,
      // Total neighbors count
      totalNeighbors: 0,
      // Whether this bot has finished exploring this cell
      cellDone: new Set(),
      // Edge traversal tracking
      edgesUsed: new Set(),
      // Current step in backtracking
      backtrackStep: 0,
      // Backtrack path
      backtrackPath: [],
      // Whether this bot is done
      done: false
    };
  }

  // --- Game state ---
  let maze = null;
  let bots = [];
  let elapsed = 0;
  let finished = false;
  let completedCount = 0;
  let lastFinishTick = 0;
  let spawn = { r: 0, c: 0 };
  let exit = { r: MAZE_ROWS - 1, c: MAZE_COLS - 1 };
  let animFrame = null;
  let lastTickTime = 0;
  let tickAccumulator = 0;
  let tickSpeed = 100; // ms per tick
  let isPaused = false;

  // --- Canvas setup ---
  const canvas = document.getElementById('maze');
  const ctx = canvas.getContext('2d');
  canvas.width = CANVAS_SIZE;
  canvas.height = CANVAS_SIZE;

  // --- DOM refs ---
  const completedEl = document.getElementById('completed');
  const timerEl = document.getElementById('timer');
  const resetBtn = document.getElementById('reset');

  // --- Initialize game ---
  function init(seed) {
    const rng = mulberry32(seed || 42);
    maze = generateMaze(MAZE_ROWS, MAZE_COLS, rng);
    spawn = { r: 0, c: 0 };
    exit = { r: MAZE_ROWS - 1, c: MAZE_COLS - 1 };
    elapsed = 0;
    finished = false;
    completedCount = 0;
    lastFinishTick = 0;

    bots = [];
    for (let i = 0; i < NUM_BOTS; i++) {
      bots.push(createBot(i, seed ? seed + i + 1 : i + 1, MAZE_ROWS, MAZE_COLS));
    }

    // Update display
    completedEl.textContent = '0';
    timerEl.textContent = '0';
    draw();
  }

  // --- Get walls for a cell ---
  function getWalls(r, c) {
    if (r < 0 || r >= MAZE_ROWS || c < 0 || c >= MAZE_COLS) {
      return { n: true, e: true, s: true, w: true };
    }
    return {
      n: maze[r][c].n,
      e: maze[r][c].e,
      s: maze[r][c].s,
      w: maze[r][c].w
    };
  }

  // --- Check if two cells are connected ---
  function isConnected(r1, c1, r2, c2) {
    if (r1 === r2 && c1 === c2) return true;
    if (r1 === r2 + 1 && c1 === c2) return !maze[r1][c1].n;
    if (r1 === r2 - 1 && c1 === c2) return !maze[r2][c2].n;
    if (c1 === c2 + 1 && r1 === r2) return !maze[r1][c1].w;
    if (c1 === c2 - 1 && r1 === r2) return !maze[r2][c2].w;
    return false;
  }

  // --- Check if edge has been traversed by bot ---
  function edgeKey(r1, c1, r2, c2) {
    return r1 + ',' + c1 + ',' + r2 + ',' + c2;
  }

  // --- Bot step ---
  function botStep(bot) {
    if (bot.done) return;

    // Check if at exit
    if (bot.r === exit.r && bot.c === exit.c) {
      bot.done = true;
      bot.finishTick = elapsed;
      return;
    }

    if (bot.state === 'backtracking') {
      // Move toward backtrack target
      if (bot.backtrackPath.length === 0) {
        // Backtracking complete, resume exploring
        bot.state = 'exploring';
        bot.backtrackTarget = null;
        bot.backtrackStep = 0;
        bot.backtrackPath = [];
        // Try to explore from current cell
        botExplore(bot);
        return;
      }

      const target = bot.backtrackPath[0];
      // Move one step toward target
      const dr = Math.sign(target.r - bot.r);
      const dc = Math.sign(target.c - bot.c);
      const nr = bot.r + dr;
      const nc = bot.c + dc;

      // Record edge traversal
      const ek = edgeKey(bot.r, bot.c, nr, nc);
      if (!bot.edgesUsed.has(ek)) {
        bot.edgesUsed.add(ek);
      }

      bot.r = nr;
      bot.c = nc;
      bot.path.push({ r: nr, c: nc });

      // Check if we reached the backtrack target
      if (nr === target.r && nc === target.c) {
        bot.backtrackPath.shift();
        // Now try to explore from this cell
        botExplore(bot);
      }
      return;
    }

    // Exploring state
    botExplore(bot);
  }

  function botExplore(bot) {
    if (bot.done) return;

    const key = bot.r + ',' + bot.c;
    if (bot.cellDone.has(key)) return;

    // Get all valid neighbors
    const dirs = [
      { dr: -1, dc: 0, wall: 'n' },
      { dr: 0, dc: 1, wall: 'e' },
      { dr: 1, dc: 0, wall: 's' },
      { dr: 0, dc: -1, wall: 'w' }
    ];

    const neighbors = [];
    for (const d of dirs) {
      const nr = bot.r + d.dr;
      const nc = bot.c + d.dc;
      if (nr >= 0 && nr < MAZE_ROWS && nc >= 0 && nc < MAZE_COLS) {
        if (isConnected(bot.r, bot.c, nr, nc)) {
          neighbors.push({ r: nr, c: nc, dir: d });
        }
      }
    }

    // Check which neighbors are unexplored (not in explored set)
    const unexplored = neighbors.filter(n => {
      const nk = n.r + ',' + n.c;
      return !bot.explored.has(nk);
    });

    // Also check edge traversal limit
    const validUnexplored = unexplored.filter(n => {
      const ek = edgeKey(bot.r, bot.c, n.r, n.c);
      return !bot.edgesUsed.has(ek);
    });

    if (validUnexplored.length > 0) {
      // Pick next unexplored neighbor using bot's direction preference
      let chosen = null;
      for (const di of bot.dirOrder) {
        for (const n of validUnexplored) {
          const dIdx = dirs.findIndex(d => d.dr === n.dir.dr && d.dc === n.dir.dc);
          if (dIdx === di) {
            chosen = n;
            break;
          }
        }
        if (chosen) break;
      }
      if (!chosen) chosen = validUnexplored[0];

      // Move to chosen neighbor
      const nr = chosen.r;
      const nc = chosen.c;
      const ek = edgeKey(bot.r, bot.c, nr, nc);
      bot.edgesUsed.add(ek);

      bot.r = nr;
      bot.c = nc;
      bot.path.push({ r: nr, c: nc });

      // Push to stack
      bot.stack.push({ r: bot.r, c: bot.c });

      // Mark current cell as having one more explored neighbor
      const curKey = (bot.r - chosen.dir.dr) + ',' + (bot.c - chosen.dir.dc);
      // Actually, we need to track explored neighbors differently
      // Let's use a different approach: track which neighbors have been visited
    } else {
      // All neighbors explored or edges used up - this is a dead end
      // Mark current cell as done
      const curKey = bot.r + ',' + bot.c;
      bot.cellDone.add(curKey);
      bot.explored.add(curKey);

      // Check if all neighbors are explored
      let allNeighborsExplored = true;
      for (const n of neighbors) {
        const nk = n.r + ',' + n.c;
        if (!bot.explored.has(nk)) {
          allNeighborsExplored = false;
          break;
        }
      }

      if (allNeighborsExplored || neighbors.length === 0) {
        // Dead end - backtrack
        bot.deadEnds.push({ r: bot.r, c: bot.c });

        if (bot.stack.length <= 1) {
          // Can't backtrack further - bot is stuck (shouldn't happen in a perfect maze)
          bot.done = true;
          bot.finishTick = elapsed;
          return;
        }

        // Pop from stack to find backtrack target
        bot.stack.pop();
        const target = bot.stack[bot.stack.length - 1];

        // Build backtrack path
        bot.backtrackPath = [];
        let cr = bot.r, cc = bot.c;
        while (cr !== target.r || cc !== target.c) {
          // Find path back using maze connectivity
          let moved = false;
          const backDirs = [
            { dr: -1, dc: 0, wall: 'n' },
            { dr: 0, dc: -1, wall: 'w' },
            { dr: 1, dc: 0, wall: 's' },
            { dr: 0, dc: 1, wall: 'e' }
          ];
          for (const bd of backDirs) {
            const br = cr + bd.dr;
            const bc = cc + bd.dc;
            if (br >= 0 && br < MAZE_ROWS && bc >= 0 && bc < MAZE_COLS) {
              if (isConnected(cr, cc, br, bc)) {
                // Check if this edge hasn't been used more than twice
                const ek = edgeKey(cr, cc, br, bc);
                if (!bot.edgesUsed.has(ek)) {
                  bot.backtrackPath.push({ r: br, c: bc });
                  cr = br;
                  cc = bc;
                  moved = true;
                  break;
                }
              }
            }
          }
          if (!moved) break;
        }

        if (bot.backtrackPath.length > 0) {
          bot.state = 'backtracking';
          // Move one step along backtrack path
          const target = bot.backtrackPath[0];
          const dr = Math.sign(target.r - bot.r);
          const dc = Math.sign(target.c - bot.c);
          const nr = bot.r + dr;
          const nc = bot.c + dc;
          const ek = edgeKey(bot.r, bot.c, nr, nc);
          bot.edgesUsed.add(ek);
          bot.r = nr;
          bot.c = nc;
          bot.path.push({ r: nr, c: nc });
          bot.backtrackPath.shift();
        } else {
          // Can't find backtrack path, mark done
          bot.done = true;
          bot.finishTick = elapsed;
        }
      } else {
        // Not all neighbors explored yet, but no valid unexplored edges
        // This means some neighbors are unexplored but their edges are used up
        // Mark as done and try to backtrack
        bot.cellDone.add(curKey);
        bot.deadEnds.push({ r: bot.r, c: bot.c });

        if (bot.stack.length <= 1) {
          bot.done = true;
          bot.finishTick = elapsed;
          return;
        }

        bot.stack.pop();
        const target = bot.stack[bot.stack.length - 1];

        bot.backtrackPath = [];
        let cr = bot.r, cc = bot.c;
        while (cr !== target.r || cc !== target.c) {
          let moved = false;
          const backDirs = [
            { dr: -1, dc: 0, wall: 'n' },
            { dr: 0, dc: -1, wall: 'w' },
            { dr: 1, dc: 0, wall: 's' },
            { dr: 0, dc: 1, wall: 'e' }
          ];
          for (const bd of backDirs) {
            const br = cr + bd.dr;
            const bc = cc + bd.dc;
            if (br >= 0 && br < MAZE_ROWS && bc >= 0 && bc < MAZE_COLS) {
              if (isConnected(cr, cc, br, bc)) {
                const ek = edgeKey(cr, cc, br, bc);
                if (!bot.edgesUsed.has(ek)) {
                  bot.backtrackPath.push({ r: br, c: bc });
                  cr = br;
                  cc = bc;
                  moved = true;
                  break;
                }
              }
            }
          }
          if (!moved) break;
        }

        if (bot.backtrackPath.length > 0) {
          bot.state = 'backtracking';
          const target = bot.backtrackPath[0];
          const dr = Math.sign(target.r - bot.r);
          const dc = Math.sign(target.c - bot.c);
          const nr = bot.r + dr;
          const nc = bot.c + dc;
          const ek = edgeKey(bot.r, bot.c, nr, nc);
          bot.edgesUsed.add(ek);
          bot.r = nr;
          bot.c = nc;
          bot.path.push({ r: nr, c: nc });
          bot.backtrackPath.shift();
        } else {
          bot.done = true;
          bot.finishTick = elapsed;
        }
      }
    }
  }

  // --- Tick ---
  function tick(n) {
    if (finished) return;

    for (let i = 0; i < n; i++) {
      // Update bot positions for smooth rendering
      for (const bot of bots) {
        bot.displayR += (bot.r - bot.displayR) * 0.5;
        bot.displayC += (bot.c - bot.displayC) * 0.5;
      }

      // Step each bot
      for (const bot of bots) {
        if (!bot.done) {
          botStep(bot);
        }
      }

      elapsed++;

      // Check completion
      let allDone = true;
      let lastBotTick = 0;
      for (const bot of bots) {
        if (!bot.done) {
          allDone = false;
          if (bot.finishTick !== null) {
            lastBotTick = Math.max(lastBotTick, bot.finishTick);
          }
        } else if (bot.finishTick !== null) {
          lastBotTick = Math.max(lastBotTick, bot.finishTick);
        }
      }

      completedCount = bots.filter(b => b.done).length;

      if (allDone) {
        finished = true;
        lastFinishTick = elapsed;
      }
    }

    // Final position update
    for (const bot of bots) {
      bot.displayR = bot.r;
      bot.displayC = bot.c;
    }

    // Update DOM
    completedEl.textContent = completedCount;
    timerEl.textContent = elapsed;
    draw();
  }

  // --- Draw ---
  function draw() {
    ctx.clearRect(0, 0, CANVAS_SIZE, CANVAS_SIZE);

    // Background
    ctx.fillStyle = '#0a0a1a';
    ctx.fillRect(0, 0, CANVAS_SIZE, CANVAS_SIZE);

    // Draw cells
    for (let r = 0; r < MAZE_ROWS; r++) {
      for (let c = 0; c < MAZE_COLS; c++) {
        const x = c * CELL_SIZE + WALL_THICKNESS;
        const y = r * CELL_SIZE + WALL_THICKNESS;

        // Cell background
        ctx.fillStyle = '#16213e';
        ctx.fillRect(x, y, CELL_SIZE, CELL_SIZE);
      }
    }

    // Draw exit
    const ex = exit.c * CELL_SIZE + WALL_THICKNESS;
    const ey = exit.r * CELL_SIZE + WALL_THICKNESS;
    ctx.fillStyle = '#e94560';
    ctx.fillRect(ex + 2, ey + 2, CELL_SIZE - 4, CELL_SIZE - 4);
    ctx.fillStyle = '#fff';
    ctx.font = 'bold 14px sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillText('★', ex + CELL_SIZE / 2, ey + CELL_SIZE / 2);

    // Draw spawn
    const sx = spawn.c * CELL_SIZE + WALL_THICKNESS;
    const sy = spawn.r * CELL_SIZE + WALL_THICKNESS;
    ctx.fillStyle = '#0f3460';
    ctx.fillRect(sx + 2, sy + 2, CELL_SIZE - 4, CELL_SIZE - 4);
    ctx.fillStyle = '#fff';
    ctx.fillText('S', sx + CELL_SIZE / 2, sy + CELL_SIZE / 2);

    // Draw walls
    ctx.strokeStyle = '#e94560';
    ctx.lineWidth = WALL_THICKNESS;
    ctx.lineCap = 'round';

    for (let r = 0; r < MAZE_ROWS; r++) {
      for (let c = 0; c < MAZE_COLS; c++) {
        const x = c * CELL_SIZE + WALL_THICKNESS;
        const y = r * CELL_SIZE + WALL_THICKNESS;

        if (maze[r][c].s && r < MAZE_ROWS - 1) {
          ctx.beginPath();
          ctx.moveTo(x, y + CELL_SIZE);
          ctx.lineTo(x + CELL_SIZE, y + CELL_SIZE);
          ctx.stroke();
        }
        if (maze[r][c].e && c < MAZE_COLS - 1) {
          ctx.beginPath();
          ctx.moveTo(x + CELL_SIZE, y);
          ctx.lineTo(x + CELL_SIZE, y + CELL_SIZE);
          ctx.stroke();
        }
      }
    }
    // Top and left outer walls
    ctx.beginPath();
    ctx.moveTo(WALL_THICKNESS, WALL_THICKNESS);
    ctx.lineTo(WALL_THICKNESS + MAZE_COLS * CELL_SIZE, WALL_THICKNESS);
    ctx.stroke();
    ctx.beginPath();
    ctx.moveTo(WALL_THICKNESS, WALL_THICKNESS);
    ctx.lineTo(WALL_THICKNESS, WALL_THICKNESS + MAZE_ROWS * CELL_SIZE);
    ctx.stroke();
    // Right and bottom outer walls
    ctx.beginPath();
    ctx.moveTo(WALL_THICKNESS + MAZE_COLS * CELL_SIZE, WALL_THICKNESS);
    ctx.lineTo(WALL_THICKNESS + MAZE_COLS * CELL_SIZE, WALL_THICKNESS + MAZE_ROWS * CELL_SIZE);
    ctx.stroke();
    ctx.beginPath();
    ctx.moveTo(WALL_THICKNESS, WALL_THICKNESS + MAZE_ROWS * CELL_SIZE);
    ctx.lineTo(WALL_THICKNESS + MAZE_COLS * CELL_SIZE, WALL_THICKNESS + MAZE_ROWS * CELL_SIZE);
    ctx.stroke();

    // Draw bots
    for (const bot of bots) {
      const bx = bot.displayC * CELL_SIZE + WALL_THICKNESS + CELL_SIZE / 2;
      const by = bot.displayR * CELL_SIZE + WALL_THICKNESS + CELL_SIZE / 2;
      const radius = bot.done ? 4 : 5;

      ctx.beginPath();
      ctx.arc(bx, by, radius, 0, Math.PI * 2);
      ctx.fillStyle = bot.done ? '#4ecca3' : bot.color;
      ctx.fill();

      if (!bot.done) {
        ctx.strokeStyle = '#fff';
        ctx.lineWidth = 1;
        ctx.stroke();
      }
    }
  }

  // --- Animation loop ---
  function animate(timestamp) {
    if (!lastTickTime) lastTickTime = timestamp;
    const delta = timestamp - lastTickTime;

    if (!finished && !isPaused) {
      tickAccumulator += delta;
      while (tickAccumulator >= tickSpeed) {
        tick(1);
        tickAccumulator -= tickSpeed;
      }
    }

    // Smooth interpolation
    if (!finished) {
      for (const bot of bots) {
        bot.displayR += (bot.r - bot.displayR) * 0.3;
        bot.displayC += (bot.c - bot.displayC) * 0.3;
      }
      draw();
    }

    animFrame = requestAnimationFrame(animate);
  }

  // --- Reset ---
  function reset(seed) {
    if (animFrame) {
      cancelAnimationFrame(animFrame);
    }
    init(seed);
    lastTickTime = 0;
    tickAccumulator = 0;
    isPaused = false;
    animFrame = requestAnimationFrame(animate);
  }

  // --- Public API ---
  window.game = {
    tick: function(n) {
      tick(n);
    },
    reset: function(seed) {
      reset(seed);
    },
    get elapsed() {
      return elapsed;
    },
    get size() {
      return { rows: MAZE_ROWS, cols: MAZE_COLS };
    },
    get spawn() {
      return { r: spawn.r, c: spawn.c };
    },
    get exit() {
